// Version minimaliste de Chart.js pour Carbonely
// Seulement les fonctionnalités nécessaires pour les 5 types de graphiques

(function(){
    // Enveloppe pour éviter les conflits
    window.Chart = function(ctx, config) {
        return new ChartInstance(ctx, config);
    };
    
    Chart.register = function() {};
    
    class ChartInstance {
        constructor(ctx, config) {
            this.ctx = ctx;
            this.config = config;
            this.data = config.data;
            this.options = config.options || {};
            this.init();
        }
        
        init() {
            this.width = this.ctx.canvas.width;
            this.height = this.ctx.canvas.height;
            this.render();
        }
        
        render() {
            const type = this.config.type;
            
            switch(type) {
                case 'pie':
                case 'doughnut':
                    this.renderPieChart();
                    break;
                case 'bar':
                    this.renderBarChart();
                    break;
                case 'line':
                    this.renderLineChart();
                    break;
                case 'scatter':
                    this.renderScatterChart();
                    break;
                default:
                    console.error('Type de graphique non supporté:', type);
            }
        }
        
        renderPieChart() {
            const ctx = this.ctx;
            const data = this.data;
            const total = data.datasets[0].data.reduce((a, b) => a + b, 0);
            const centerX = this.width / 2;
            const centerY = this.height / 2;
            const radius = Math.min(centerX, centerY) * 0.8;
            
            let startAngle = 0;
            
            data.datasets[0].data.forEach((value, i) => {
                const sliceAngle = (value / total) * 2 * Math.PI;
                const color = data.datasets[0].backgroundColor[i] || '#ccc';
                
                ctx.beginPath();
                ctx.moveTo(centerX, centerY);
                ctx.arc(centerX, centerY, radius, startAngle, startAngle + sliceAngle);
                ctx.closePath();
                
                ctx.fillStyle = color;
                ctx.fill();
                ctx.strokeStyle = '#fff';
                ctx.lineWidth = 2;
                ctx.stroke();
                
                startAngle += sliceAngle;
            });
            
            // Légende
            if (this.options.plugins?.legend?.display !== false) {
                this.renderLegend();
            }
        }
        
        renderBarChart() {
            const ctx = this.ctx;
            const data = this.data;
            const labels = data.labels;
            const datasets = data.datasets;
            
            const barWidth = (this.width * 0.8) / labels.length / datasets.length;
            const maxValue = Math.max(...datasets.flatMap(d => d.data));
            
            datasets.forEach((dataset, datasetIndex) => {
                ctx.fillStyle = dataset.backgroundColor || '#2b6cb0';
                
                labels.forEach((label, labelIndex) => {
                    const value = dataset.data[labelIndex];
                    const barHeight = (value / maxValue) * (this.height * 0.7);
                    const x = (this.width * 0.1) + (labelIndex * (this.width * 0.8) / labels.length) + (datasetIndex * barWidth);
                    const y = this.height * 0.9 - barHeight;
                    
                    ctx.fillRect(x, y, barWidth * 0.8, barHeight);
                    
                    if (dataset.borderRadius) {
                        // Arrondi simplifié
                        ctx.beginPath();
                        ctx.roundRect(x, y, barWidth * 0.8, barHeight, 4);
                        ctx.fill();
                    }
                });
            });
        }
        
        renderLineChart() {
            const ctx = this.ctx;
            const data = this.data;
            const labels = data.labels;
            const datasets = data.datasets;
            
            const maxValue = Math.max(...datasets.flatMap(d => d.data));
            const padding = this.height * 0.1;
            
            datasets.forEach(dataset => {
                ctx.beginPath();
                ctx.strokeStyle = dataset.borderColor || '#2b6cb0';
                ctx.lineWidth = dataset.borderWidth || 2;
                
                labels.forEach((label, i) => {
                    const value = dataset.data[i];
                    const x = (i / (labels.length - 1)) * (this.width * 0.8) + (this.width * 0.1);
                    const y = this.height - padding - (value / maxValue) * (this.height - padding * 2);
                    
                    if (i === 0) {
                        ctx.moveTo(x, y);
                    } else {
                        ctx.lineTo(x, y);
                    }
                });
                
                ctx.stroke();
                
                if (dataset.fill) {
                    ctx.lineTo(this.width * 0.9, this.height - padding);
                    ctx.lineTo(this.width * 0.1, this.height - padding);
                    ctx.closePath();
                    ctx.fillStyle = dataset.backgroundColor || 'rgba(66, 153, 225, 0.1)';
                    ctx.fill();
                }
            });
        }
        
        renderScatterChart() {
            const ctx = this.ctx;
            const data = this.data;
            const datasets = data.datasets;
            
            const maxX = Math.max(...datasets[0].data.map(d => d.x));
            const maxY = Math.max(...datasets[0].data.map(d => d.y));
            const padding = this.height * 0.1;
            
            datasets.forEach(dataset => {
                dataset.data.forEach(point => {
                    const x = (point.x / maxX) * (this.width * 0.8) + (this.width * 0.1);
                    const y = this.height - padding - (point.y / maxY) * (this.height - padding * 2);
                    
                    ctx.beginPath();
                    ctx.arc(x, y, dataset.pointRadius || 6, 0, Math.PI * 2);
                    ctx.fillStyle = dataset.backgroundColor || 'rgba(255, 99, 132, 0.5)';
                    ctx.fill();
                    ctx.strokeStyle = dataset.borderColor || 'rgba(255, 99, 132, 1)';
                    ctx.lineWidth = dataset.borderWidth || 1;
                    ctx.stroke();
                });
            });
        }
        
        renderLegend() {
            // Légende simplifiée
            const ctx = this.ctx;
            const data = this.data;
            const labels = data.labels;
            const colors = data.datasets[0].backgroundColor;
            
            ctx.font = '12px sans-serif';
            
            labels.forEach((label, i) => {
                const x = 20;
                const y = 20 + i * 25;
                
                ctx.fillStyle = colors[i] || '#ccc';
                ctx.fillRect(x, y - 8, 15, 15);
                
                ctx.fillStyle = '#333';
                ctx.fillText(label, x + 20, y);
            });
        }
        
        update(mode = 'default') {
            this.clear();
            this.render();
        }
        
        resize() {
            // Redimensionnement simplifié
            this.render();
        }
        
        clear() {
            this.ctx.clearRect(0, 0, this.width, this.height);
        }
        
        toBase64Image() {
            return this.ctx.canvas.toDataURL('image/png');
        }
    }
    
    // Support pour roundRect
    if (!CanvasRenderingContext2D.prototype.roundRect) {
        CanvasRenderingContext2D.prototype.roundRect = function(x, y, width, height, radius) {
            if (width < 2 * radius) radius = width / 2;
            if (height < 2 * radius) radius = height / 2;
            this.beginPath();
            this.moveTo(x + radius, y);
            this.arcTo(x + width, y, x + width, y + height, radius);
            this.arcTo(x + width, y + height, x, y + height, radius);
            this.arcTo(x, y + height, x, y, radius);
            this.arcTo(x, y, x + width, y, radius);
            this.closePath();
            return this;
        }
    }
})();